/**
 * Branch resolution by reading `.git/HEAD` — no subprocess, ever.
 *
 * LEAF MODULE BY DESIGN: this file imports ONLY `node:fs` and `node:path`.
 * It must never import another lib/ module. `env.ts` already imports
 * `session-id-generator.ts`, so parking this helper in either of them and
 * importing it from the other creates a cycle (undefined-at-import-time in
 * the esbuild bundle). A leaf cannot cycle, so the constraint is structural
 * rather than a rule someone has to remember (#2970).
 *
 * Why parsing beats spawning: every hook runs in a fresh process, so any
 * in-memory cache is always cold and each call paid a real
 * `execFileSync('git', ['branch', '--show-current'])`. Under fork pressure and
 * `index.lock` contention from concurrent sessions, that spawn ran for
 * seconds; production timing records showed 8-10s exec times against a 5s
 * hook budget (#2948). HEAD is a one-line symref file: reading it takes no
 * locks and cannot stall.
 */

import { readFileSync, statSync } from 'node:fs';
import { join, resolve } from 'node:path';

/**
 * Read the current branch by parsing `.git/HEAD`.
 *
 * Matches `git branch --show-current` semantics exactly:
 *   - on a branch     -> the branch name
 *   - detached HEAD   -> '' (empty string)
 *
 * Throws when there is no readable `.git` (missing repo, malformed pointer
 * file). Callers map that to their own fallback, and the two failure modes
 * are deliberately distinct: '' means "repo, no branch", a throw means "no
 * repo". Collapsing them would change caller behavior.
 *
 * Handles linked worktrees and submodules, where `.git` is a FILE containing
 * `gitdir: <path>` rather than a directory.
 */
export function readBranchFromHead(dir: string): string {
  let gitDir = join(dir, '.git');
  if (statSync(gitDir).isFile()) {
    const pointer = readFileSync(gitDir, 'utf8');
    const m = pointer.match(/^gitdir:\s*(.+)\s*$/m);
    if (!m) throw new Error('malformed .git pointer file');
    gitDir = resolve(dir, m[1].trim());
  }
  const head = readFileSync(join(gitDir, 'HEAD'), 'utf8').trim();
  const ref = head.match(/^ref:\s*refs\/heads\/(.+)$/);
  return ref ? ref[1] : ''; // detached HEAD -> '' (same as --show-current)
}

/**
 * Branch, or a caller-supplied fallback when there is no readable repo.
 *
 * Convenience for the several call sites that only care about "a usable
 * string", each of which previously wrapped its own spawn in try/catch with
 * a different fallback ('unknown' / 'nobranch').
 */
export function readBranchOr(dir: string, fallback: string): string {
  try {
    return readBranchFromHead(dir);
  } catch {
    return fallback;
  }
}
